func (t *anthropicStreamTranslator) appendAccumulatedText(delta string) {
	if delta == "" {
		return
	}
	t.accumulatedText += delta
	const maxChars = 64 * 1024
	if len(t.accumulatedText) > maxChars {
		t.accumulatedText = t.accumulatedText[len(t.accumulatedText)-maxChars:]
	}
}

