func (t *anthropicStreamTranslator) recoverToolCallsFromText(reason string) (int, error) {
	if strings.TrimSpace(t.accumulatedText) == "" {
		return 0, nil
	}
	if reason == "tool_calls" || len(t.toolCalls) > 0 || len(t.responsesTools) > 0 {
		return 0, nil
	}

	candidates := extractToolCallsFromText(t.accumulatedText)
	if len(candidates) == 0 {
		return 0, nil
	}

	emitted := 0
	for _, candidate := range candidates {
		args, toolName, ok := validateAndRepairRecoveredToolCall(candidate, t.toolSchemas, t.accumulatedText)
		if !ok {
			continue
		}
		if err := t.emitRecoveredToolCall(toolName, args); err != nil {
			return emitted, err
		}
		emitted++
	}
	return emitted, nil
}

func (t *anthropicStreamTranslator) emitRecoveredToolCall(name string, args map[string]any) error {
	toolID := fmt.Sprintf("toolu_recovered_%d_%d", time.Now().UnixNano(), t.contentIndex)

	if err := t.enqueueEvent(&AnthropicStreamEvent{
		Type:  "content_block_start",
		Index: ptrInt64(t.contentIndex),
		ContentBlock: &AnthropicMessageContentBlock{
			Type:  "tool_use",
			ID:    toolID,
			Name:  ptrStr(name),
			Input: json.RawMessage("{}"),
		},
	}); err != nil {
		return err
	}

	argsJSON, err := json.Marshal(args)
	if err != nil {
		argsJSON = []byte("{}")
	}
	if err := t.enqueueEvent(&AnthropicStreamEvent{
		Type:  "content_block_delta",
		Index: ptrInt64(t.contentIndex),
		Delta: &AnthropicStreamDelta{
			Type:        ptrStr("input_json_delta"),
			PartialJSON: ptrStr(string(argsJSON)),
		},
	}); err != nil {
		return err
	}

	if err := t.enqueueEvent(&AnthropicStreamEvent{
		Type:  "content_block_stop",
		Index: ptrInt64(t.contentIndex),
	}); err != nil {
		return err
	}

	t.contentIndex++
	return nil
}

